<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Email Confirmation</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <script>
        tailwind.config = {
            theme: {
                extend: {
                    colors: {
                        primary: '#5D5CDE',
                    }
                }
            },
            darkMode: 'class'
        }

        // Dark mode detection
        if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
            document.documentElement.classList.add('dark');
        }
        window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', event => {
            if (event.matches) {
                document.documentElement.classList.add('dark');
            } else {
                document.documentElement.classList.remove('dark');
            }
        });
    </script>
</head>
<body class="bg-white dark:bg-gray-900 min-h-screen">
    <div class="container mx-auto px-4 py-8 max-w-2xl">
        <div class="bg-white dark:bg-gray-800 rounded-lg shadow-md overflow-hidden">
            <!-- Email Header -->
            <div class="bg-primary text-white p-4">
                <h1 class="text-xl font-bold">New Email Message</h1>
            </div>

            <!-- Email Form -->
            <div class="p-6">
                <div class="space-y-4">
                    <!-- To Field -->
                    <div class="flex flex-col sm:flex-row gap-2">
                        <label for="to" class="text-gray-700 dark:text-gray-300 font-semibold w-20">To:</label>
                        <input type="text" id="to" value="John" class="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md text-base bg-white dark:bg-gray-700 text-gray-900 dark:text-white" readonly>
                    </div>

                    <!-- Subject Field -->
                    <div class="flex flex-col sm:flex-row gap-2">
                        <label for="subject" class="text-gray-700 dark:text-gray-300 font-semibold w-20">Subject:</label>
                        <input type="text" id="subject" value="RE: Birthday Party Details - RSVP Needed" class="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md text-base bg-white dark:bg-gray-700 text-gray-900 dark:text-white">
                    </div>

                    <!-- Message Field -->
                    <div class="flex flex-col gap-2">
                        <label for="message" class="text-gray-700 dark:text-gray-300 font-semibold">Message:</label>
                        <textarea id="message" rows="8" class="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md text-base bg-white dark:bg-gray-700 text-gray-900 dark:text-white">Hi John,

confirmation

Thanks for the invitation to Emma's birthday party. I'm looking forward to celebrating with you all at Funtime Play Center on November 20th.

Best regards,</textarea>
                    </div>

                    <!-- Send Button -->
                    <div class="flex justify-end mt-4">
                        <button id="sendBtn" class="bg-primary hover:bg-primary/90 text-white font-semibold py-2 px-6 rounded-md transition-colors">
                            Send Email
                        </button>
                    </div>
                </div>
            </div>
        </div>

        <!-- Email Sent Notification -->
        <div id="notification" class="mt-6 hidden bg-green-100 dark:bg-green-900 border border-green-200 dark:border-green-700 text-green-800 dark:text-green-200 px-4 py-3 rounded-md">
            <div class="flex items-center">
                <svg class="w-5 h-5 mr-2" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
                    <path fill-rule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clip-rule="evenodd"></path>
                </svg>
                <p>Your RSVP confirmation has been sent successfully!</p>
            </div>
        </div>

        <!-- Note -->
        <div class="mt-6 text-sm text-gray-600 dark:text-gray-400 italic">
            <p>Note: This is a simulated email interface. No actual email will be sent.</p>
        </div>
    </div>

    <script>
        document.getElementById('sendBtn').addEventListener('click', function() {
            const messageText = document.getElementById('message').value;

            // Validation to ensure "confirmation" is in the message
            if (!messageText.includes('confirmation')) {
                alert('Your message must include the word "confirmation" as requested.');
                return;
            }

            // Show notification
            document.getElementById('notification').classList.remove('hidden');

            // Scroll to notification
            document.getElementById('notification').scrollIntoView({ behavior: 'smooth' });

            // Disable send button to prevent multiple sends
            this.disabled = true;
            this.classList.add('opacity-50', 'cursor-not-allowed');
        });
    </script>
</body>
</html>

